import{_ as a,o as r,c as t,ag as n}from"./chunks/framework.OsDJF_Ea.js";const p=JSON.parse('{"title":"Granular Techniques","description":"","frontmatter":{},"headers":[],"relativePath":"guides/granular.md","filePath":"guides/granular.md"}'),o={name:"guides/granular.md"};function i(s,e,l,d,u,h){return r(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="granular-techniques" tabindex="-1">Granular Techniques <a class="header-anchor" href="#granular-techniques" aria-label="Permalink to &quot;Granular Techniques&quot;">​</a></h1><p>Granular synthesis breaks audio into tiny fragments (grains) and reassembles them. The Smart Contact Mic has three granular modules for different use cases.</p><h2 id="granular-basic" tabindex="-1">Granular (Basic) <a class="header-anchor" href="#granular-basic" aria-label="Permalink to &quot;Granular (Basic)&quot;">​</a></h2><p>The simplest granular module. Records incoming audio into a buffer and plays back 4 grains with variable size and randomisation.</p><p><strong>Good for:</strong> Simple texture creation, pitch shifting, freeze effects.</p><h2 id="granular-cloud" tabindex="-1">Granular Cloud <a class="header-anchor" href="#granular-cloud" aria-label="Permalink to &quot;Granular Cloud&quot;">​</a></h2><p>4-layer granular with a shared 500ms buffer. Each layer can be frozen independently.</p><p><strong>Good for:</strong> Layered textures, ambient soundscapes, controlled grain manipulation.</p><h3 id="auto-mapped-controls" tabindex="-1">Auto-Mapped Controls <a class="header-anchor" href="#auto-mapped-controls" aria-label="Permalink to &quot;Auto-Mapped Controls&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Control</th><th>Function</th></tr></thead><tbody><tr><td>Pot 1</td><td>Grain density</td></tr><tr><td>Pot 2</td><td>Grain size</td></tr><tr><td>Pot 3</td><td>Pitch</td></tr><tr><td>Pot 4</td><td>Dry/Wet mix</td></tr><tr><td>Buttons 1-4</td><td>Freeze layers 1-4</td></tr></tbody></table><h2 id="granular-dense" tabindex="-1">Granular Dense <a class="header-anchor" href="#granular-dense" aria-label="Permalink to &quot;Granular Dense&quot;">​</a></h2><p>The most powerful granular module with 20 concurrent grains, stereo spread, and cloud panning.</p><p><strong>Good for:</strong> Dense clouds, spectral smearing, dramatic transformations.</p><h2 id="common-techniques" tabindex="-1">Common Techniques <a class="header-anchor" href="#common-techniques" aria-label="Permalink to &quot;Common Techniques&quot;">​</a></h2><h3 id="freeze" tabindex="-1">Freeze <a class="header-anchor" href="#freeze" aria-label="Permalink to &quot;Freeze&quot;">​</a></h3><p>Send audio into a granular module, then freeze the buffer. The grains continue to play from the frozen audio while new input is ignored. Unfreeze to capture new material.</p><h3 id="pitch-shifting" tabindex="-1">Pitch Shifting <a class="header-anchor" href="#pitch-shifting" aria-label="Permalink to &quot;Pitch Shifting&quot;">​</a></h3><p>Set the pitch parameter above or below 1.0 to shift the grain playback pitch without changing speed.</p><h3 id="texture-from-noise" tabindex="-1">Texture from Noise <a class="header-anchor" href="#texture-from-noise" aria-label="Permalink to &quot;Texture from Noise&quot;">​</a></h3><p>Feed noise into Granular Dense with small grain sizes (10-20ms) and high density. Modulate the position with an LFO for evolving texture.</p><h3 id="live-input-processing" tabindex="-1">Live Input Processing <a class="header-anchor" href="#live-input-processing" aria-label="Permalink to &quot;Live Input Processing&quot;">​</a></h3><p>Connect Stereo In to any granular module for real-time processing of external audio.</p>',22)])])}const m=a(o,[["render",i]]);export{p as __pageData,m as default};
